import React, { useState, useMemo } from 'react';
import { Calendar as BigCalendar, dateFnsLocalizer } from 'react-big-calendar';
import { format, parse, startOfWeek, getDay } from 'date-fns';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon } from 'lucide-react';
// Import React Big Calendar CSS first
import 'react-big-calendar/lib/css/react-big-calendar.css';

const locales = {
  'en-US': require('date-fns/locale/en-US'),
};

const localizer = dateFnsLocalizer({
  format,
  parse,
  startOfWeek,
  getDay,
  locales,
});

const Calendar = ({ holidays, vacations, onNavigate, currentDate, onViewChange }) => {
  const [view, setView] = useState('month');
  const [date, setDate] = useState(currentDate || new Date());

  // Combine holidays and vacations into calendar events
  const events = useMemo(() => {
    const calendarEvents = [];

    // Add holidays
    if (holidays && Array.isArray(holidays)) {
      holidays.forEach(holiday => {
        if (holiday.date) {
          calendarEvents.push({
            id: `holiday-${holiday._id || Math.random()}`,
            title: holiday.name,
            start: new Date(holiday.date),
            end: new Date(holiday.date),
            type: 'holiday',
            allDay: true,
            resource: holiday
          });
        }
      });
    }

    // Add vacations
    if (vacations && Array.isArray(vacations)) {
      vacations.forEach(vacation => {
        if (vacation.startDate && vacation.endDate) {
          calendarEvents.push({
            id: `vacation-${vacation._id || Math.random()}`,
            title: vacation.name,
            start: new Date(vacation.startDate),
            end: new Date(vacation.endDate),
            type: 'vacation',
            allDay: true,
            resource: vacation
          });
        }
      });
    }

    return calendarEvents;
  }, [holidays, vacations]);

  const eventStyleGetter = (event) => {
    let style = {
      backgroundColor: '#3B82F6', // Blue for holidays
      borderRadius: '4px',
      opacity: 0.8,
      color: 'white',
      border: '0px',
      display: 'block',
      padding: '2px 5px',
      fontSize: '12px'
    };

    if (event.type === 'vacation') {
      style.backgroundColor = '#10B981'; // Green for vacations
    }

    return { style };
  };

  // Handle navigation
  const handleNavigate = (newDate, view, action) => {
    console.log('Navigation:', action, newDate, view);
    setDate(newDate);
    if (onNavigate) {
      onNavigate(action, newDate);
    }
  };

  // Handle view change
  const handleViewChange = (newView) => {
    console.log('View change:', newView);
    setView(newView);
    if (onViewChange) {
      onViewChange(newView);
    }
  };

  // Custom toolbar component
  const CustomToolbar = (toolbar) => {
    const goToToday = () => {
      const today = new Date();
      setDate(today);
      toolbar.onNavigate('TODAY', today);
    };

    const goToPrevious = () => {
      toolbar.onNavigate('PREV');
    };

    const goToNext = () => {
      toolbar.onNavigate('NEXT');
    };

    return (
      <div className="flex items-center justify-between mb-4 p-4 bg-white rounded-lg shadow">
        <div className="flex items-center space-x-2">
          <CalendarIcon className="w-5 h-5 text-gray-600" />
          <h2 className="text-lg font-semibold text-gray-900">
            {toolbar.label}
          </h2>
        </div>

        <div className="flex items-center space-x-2">
          <button
            onClick={goToPrevious}
            className="p-2 text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded"
            title="Previous"
          >
            <ChevronLeft className="w-4 h-4" />
          </button>

          <button
            onClick={goToToday}
            className="px-3 py-1 text-sm font-medium text-blue-600 hover:text-blue-700 hover:bg-blue-50 rounded"
            title="Today"
          >
            Today
          </button>

          <button
            onClick={goToNext}
            className="p-2 text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded"
            title="Next"
          >
            <ChevronRight className="w-4 h-4" />
          </button>
        </div>

        <div className="flex items-center space-x-1">
          {['month', 'week', 'day'].map((viewOption) => (
            <button
              key={viewOption}
              onClick={() => {
                setView(viewOption);
                toolbar.onView(viewOption);
              }}
              className={`px-3 py-1 text-sm font-medium rounded ${
                view === viewOption
                  ? 'bg-blue-600 text-white'
                  : 'text-gray-600 hover:text-gray-900 hover:bg-gray-100'
              }`}
            >
              {viewOption.charAt(0).toUpperCase() + viewOption.slice(1)}
            </button>
          ))}
        </div>
      </div>
    );
  };

  // Debug logging
  console.log('Calendar render:', { view, date, eventsCount: events.length });

  return (
    <div className="bg-white rounded-lg shadow p-4">
      <BigCalendar
        localizer={localizer}
        events={events}
        startAccessor="start"
        endAccessor="end"
        style={{ height: 600 }}
        view={view}
        onView={handleViewChange}
        onNavigate={handleNavigate}
        date={date}
        toolbar={true}
        components={{
          toolbar: CustomToolbar
        }}
        eventPropGetter={eventStyleGetter}
        selectable
        popup
        defaultView="month"
        views={['month', 'week', 'day']}
        messages={{
          next: "Next",
          previous: "Previous",
          today: "Today",
          month: "Month",
          week: "Week",
          day: "Day",
          noEventsInRange: "No events in this range."
        }}
        step={60}
        timeslots={1}
      />
    </div>
  );
};

export default Calendar;
